var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"실비아 씨, 피해요!","JPN":"シルビアさん、逃げてください！","ENG":"Sylvia, watch out!","TWN":"希爾維亞，快躲開！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Hngh!","TWN":"咳！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_BLADE_BIG_05"},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"괜찮아요, 실비아 씨? 다치진 않았어요?","JPN":"大丈夫ですか、シルビアさん！　怪我は？","ENG":"Sylvia, are you okay? Are you hurt anywhere?","TWN":"妳沒事吧，希爾維亞？妳沒受傷吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"덕분에 살았어.","JPN":"おかげで助かったわ。","ENG":"You saved me.","TWN":"多虧妳救了我。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"하지만 저 자식, 실력이 너무 상식 밖이잖아?","JPN":"でもあいつ、いくらなんでも強すぎるでしょ！","ENG":"But he's ridiculously strong.","TWN":"但那個傢伙的實力，遠超出我的預想。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"예전에 봤을 때도 보통내기는 아니라고 생각했는데, 이 정도일 줄은......","JPN":"前に見たときも普通じゃないとは思ったけど、ここまでなんて……","ENG":"I knew he was strong, but not this much.","TWN":"之前我就覺得他非同尋常，沒想到竟然如此厲害……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"저것도 봐주고 있는 거예요.","JPN":"あれでも手加減しているんです。","ENG":"I don't think it's even half of what he can do.","TWN":"他還沒有使出全部實力。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제대로 싸우기 시작하면 저나 실비아 씨만으론 5분도 버티기 힘들걸요.","JPN":"本気を出したら、私やシルビアさんだけでは5分も持ちません。","ENG":"If he gets serious, neither of us might last longer than five minutes.","TWN":"如果真的打起來，妳和我估計都挺不過五分鐘。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"겨우 5분? 너무 내숭 떠는 거 아냐?","JPN":"たったの5分？　自分を卑下しすぎじゃない？","ENG":"Just five minutes? Aren't you being too modest?","TWN":"才五分鐘？這也太弱了吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"사실대로 말했을 뿐이에요. 애초에 우리 둘 다 근접 전투랑은 거리가 멀잖아요?","JPN":"いえ、それが事実です。元々私たちは近接戦闘が苦手ですからね。","ENG":"I'm only telling the truth. Neither of us is good at close quarters combat, anyway.","TWN":"沒辦法，這就是事實，而且妳和我本就不適合近戰。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 어쩌게? 이대로 당할 셈이야?","JPN":"それじゃどうするの？　このままやられるつもり？","ENG":"Then what? Should we just wait for him to dominate us?","TWN":"那怎麼辦？等著他殺了我們嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럴 리가요. 저한테 다 계획이 있죠.","JPN":"まさか、私に計画があります。","ENG":"Of course not. I've got a plan.","TWN":"當然不是，我倒是有個計畫。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"슬슬 눈치챌 시간이 됐는데......","JPN":"そろそろ、気づく頃だと思いますが……","ENG":"It's about time she noticed...","TWN":"他應該快察覺出來了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"눈치채다니, 뭘?","JPN":"気づくって、何に？","ENG":"Who's she?","TWN":"察覺什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"작전 타임은 끝나셨나요, 두 분?","JPN":"作戦タイムは終わりましたか？　お二人さん。","ENG":"Ladies, are you done strategizing?","TWN":"作戰計畫討論好了嗎，兩位？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그럼 슬슬 다시 시작을...... 음?","JPN":"そろそろ、再開しても……うん？","ENG":"Then, let's get back to—mm?","TWN":"那我們再重新開始……嗯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"에퉤퉤......! 입에 흙이 잔뜩 들어갔슴다......!","JPN":"ウエッ……！　口に砂がたくさん入ったっす……！","ENG":"*Spit, Spit!* My mouth is filled with dirt, ma'am!","TWN":"呸呸呸……！嘴裡都是土……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"다음부터는 급하다고 해서 벽 부수고 들어가지 마세요, 모네. ","JPN":"モネ！　次からはいくら急いでいても壁を壊さないでください。 ","ENG":"Mone, you shouldn't break through walls, no matter how urgent things are. ","TWN":"下次即使再著急，也不要破牆而入了，莫妮。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"싸우는 소리가 들려서 급히 달려왔습니다. 무슨 일이시죠?","JPN":"戦っている音が聞こえたので、何かあったのかと思いまして。","ENG":"We heard the sound of a fight, so we came as quickly as we could. What happened?","TWN":"我聽到了打鬥的聲音，所以過來看一下，到底發生了什麼事？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"휴우...... 너무 늦지 않아서 다행이에요, 베로니카 씨.","JPN":"ふぅ、ベロニカさん……間に合ってよかった。","ENG":"Whew, you came on time, Veronica.","TWN":"呼……貝洛妮卡，妳來的正是時候。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"메이드를 기다렸다고? 아니, 어째서?","JPN":"メイドを待ってたの？　どうして？","ENG":"You were waiting for the maids? Why?","TWN":"等那個女僕？為什麼？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그야 훌륭한 근접 전투 요원 분이시니까요.","JPN":"それはもちろん、立派な近接戦闘要員だからです。","ENG":"They're excellent melee combatants.","TWN":"因為她是一個非常優秀的近戰特工。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"실비아 님께선 분명 알리바이를 증명할 수 없어서 구금되셨던 걸로 압니다만...... ","JPN":"シルビアさんはアリバイを証明できず、拘禁されたのではありませんか……？ ","ENG":"Ms. Sylvia, I thought you were detained because you couldn't prove your alibi. ","TWN":"希爾維亞，您不是無法證實不在場證明，所以被關起來了嗎……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"어떻게 풀려나셨나요?","JPN":"どうやって抜け出したのですか？","ENG":"How were you released?","TWN":"可現在怎麼被放了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그건 애초에 모함이야! 진짜 범인은 저 사기꾼 녀석이라고!","JPN":"それは罠よ！　真犯人はあのペテン師野郎なの！","ENG":"That was a setup. The real perpetrator is that sly jerk over there!","TWN":"因為那本身就是個陰謀！那個騙子才是真凶！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"맞아요. 알리바이가 없는 건 선배도 마찬가지였어요.","JPN":"そうです。アリバイがないのは先輩も同じです。","ENG":"She's right. Shiyoon didn't have an alibi, either.","TWN":"是的，其實前輩也沒有不在場證明。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그리고 우리가 각자 떨어지자마자 본색을 드러낸 거죠.","JPN":"そしてみんなから離れた途端、本性を現したんです！","ENG":"And he showed his true colors after we were separated.","TWN":"一轉身，他便露出了真面目。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"저, 정말임까......?","JPN":"ほ、本当っすか……？","ENG":"A-are you serious, ma'am?","TWN":"真、真的嗎……？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"범인과 무관하게, 저희에겐 파티에서 일어나는 소란을 중재할 의무가 있습니다.","JPN":"誰が犯人なのかは関係ありません。\\n私たちにはパーティーでの騒ぎを仲裁する義務があります。","ENG":"Apart from the perpetrator, we're responsible for any disturbances that may occur during the party.","TWN":"無關於兇手，我們有責任解決在派對上發生的騷亂。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"그러니 세 분 모두 전투를 멈추고 무장을 해제하시길 권고드립니다.","JPN":"ですので、お三方は戦闘をお止めになり、武装を解除してください。","ENG":"So, all three of you, please stop fighting and put away your weapons.","TWN":"所以我奉勸三位停下戰鬥，解除武裝。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"그렇지 않으면 본 행사를 책임지는 메이드장으로서, 부득이하게 사태에 개입할 수밖에 없습니다.","JPN":"そうしなければイベントの責任を負っているメイド長として、不本意ながら介入せざるを得ません。","ENG":"Or, as the Chief Maid in charge of this event, I'll have to intervene.","TWN":"不然作為負責本活動的女僕長，就不得不介入此次事件中了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"든든한 방패를 둘이나 끼고 싸우긴 역시 좀 어렵겠죠. 아무래도 이번엔 제 판정패 같네요.","JPN":"頑丈な盾を二人も前にして戦うのは難しいでしょう。\\nどうやら今回は僕の判定負けのようですね。","ENG":"I don't think I can take on both shields you've brought to the fight. I'll have to give up this time.","TWN":"有兩個可靠的夥伴一同戰鬥，看來這一局我是必輸啊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"아쉽지만 전 이쯤에서 물러나야겠습니다.","JPN":"残念ですが、この辺で失礼させていただきます。","ENG":"If you'll excuse me, I'll leave now.","TWN":"可惜了，我暫且就先退出了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐? 지금 설마 도망치겠다는 거야?!","JPN":"えっ、まさか逃げる気！？","ENG":"What? Are you trying to run?","TWN":"什麼？你這意思是要逃跑啊？！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"걱정 마세요, 실비아 씨. 다시 만나게 될 겁니다.","JPN":"ご心配なく、シルビアさん。またお会いできるはずです。","ENG":"Don't worry, Sylvia. We'll meet again.","TWN":"不用擔心，希爾維亞小姐，我們以後還會再見的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"성야의 밤이 저물기엔 아직 이르니까요.","JPN":"聖夜が明けるまで、まだまだ時間はありますから。","ENG":"The Holy Night is still young.","TWN":"星夜還沒有落幕呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};